import { useState } from "react";
import axios from "../api/axios";
import { useNavigate } from "react-router-dom";

export default function AdminLogin() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState("");
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        try {
            const res = await axios.post("/auth/login", { email, password });
            if (res.data.role === "admin") {
                localStorage.setItem("token", res.data.token);
                localStorage.setItem("role", res.data.role); // Store role
                navigate("/admin");
            } else {
                setError("Access Denied: Admins Only");
            }
        } catch (err) {
            setError(err.response?.data?.message || "Login failed");
        }
    };

    return (
        <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '80vh' }}>
            <div style={{ padding: '40px', borderRadius: '15px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', background: 'white', width: '350px', border: '1px solid #e0e0e0' }}>
                <h2 style={{ textAlign: 'center', marginBottom: '20px', color: '#333' }}>🛡️ Admin Portal</h2>
                {error && <p style={{ color: 'red', textAlign: 'center', background: '#ffebee', padding: '10px', borderRadius: '5px' }}>{error}</p>}
                <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                    <input
                        type="email"
                        placeholder="Admin Email"
                        value={email}
                        onChange={e => setEmail(e.target.value)}
                        required
                        style={{ padding: '12px', borderRadius: '8px', border: '1px solid #ccc', fontSize: '16px' }}
                    />
                    <input
                        type="password"
                        placeholder="Password"
                        value={password}
                        onChange={e => setPassword(e.target.value)}
                        required
                        style={{ padding: '12px', borderRadius: '8px', border: '1px solid #ccc', fontSize: '16px' }}
                    />
                    <button type="submit" style={{ padding: '12px', borderRadius: '8px', border: 'none', background: '#d32f2f', color: 'white', fontSize: '16px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' }}>
                        Access Dashboard
                    </button>
                </form>
            </div>
        </div>
    );
}
